                    <a href="{{ route('register') }}" class="btn btn--green">S'inscrire</a>
                </div>

                <div class="nav__toggle" id="nav-toggle">
                    <i class="fas fa-bars"></i>
                </div>
            </div>
        </nav>
    </header>

    <main>
        <!-- Hero Section -->
