        <section class="features section" id="features">
            <div class="container">
                <h2 class="section__title">Pourquoi choisir Mini Bibliothèque ?</h2>
                <div class="features__grid grid">
                    <div class="card reveal">
                        <i class="fas fa-book card__icon"></i>
                        <h3>Gestion des livres</h3>
                        <p>Ajouter, modifier, supprimer et rechercher facilement vos livres.</p>
                    </div>
                    <div class="card reveal">
                        <i class="fas fa-users card__icon"></i>
                        <h3>Gestion des lecteurs</h3>
                        <p>Enregistrer les membres de la bibliothèque en toute simplicité.</p>
                    </div>
                    <div class="card reveal">
                        <i class="fas fa-sync card__icon"></i>
                        <h3>Gestion des emprunts</h3>
                        <p>Suivre les livres empruntés et retournés en temps réel.</p>
